/* ==UserStyle==
 @name           Slatewave for GitHub
 @namespace      getslatewave.com/github
 @version        0.0.1
 @description    Slate base, teal accents — Slatewave palette applied to GitHub.
 @author         Kevin Langley Jr.
 @homepageURL    https://getslatewave.com
 @supportURL     https://github.com/kevinlangleyjr/slatewave-userstyles/issues
 @license        WTFPL
==/UserStyle== */

@-moz-document domain("github.com"), domain("gist.github.com") {
  /* =============================================================
   * Slatewave for GitHub
   * Slate base, teal accents. Overrides GitHub's Primer design
   * tokens so the theme follows GitHub's UI as it evolves.
   *
   * Approach: redefine the color custom properties on every element
   * that participates in Primer's theming — the html root AND any
   * inner element that carries data-color-mode (Primer's
   * ThemeProvider mounts these deep in the tree on newer GitHub
   * surfaces, e.g. Enterprise Managed Users). Without that wider
   * net, an inner ThemeProvider re-declares the tokens after we
   * set them on html, and our values get shadowed for that subtree.
   *
   * !important is the belt-and-braces against late-injected styles
   * and higher-specificity GitHub rules that include explicit theme
   * names like data-dark-theme="dark_default".
   * ============================================================= */

  html,
  [data-color-mode],
  [data-light-theme],
  [data-dark-theme] {
    /* ---------- Slatewave palette (private, used below) ---------- */
    --slatewave-bg-0: #282c34;       /* page canvas */
    --slatewave-bg-1: #21252b;       /* cards, headers, sidebar */
    --slatewave-bg-2: #1e293b;       /* code blocks, modals, inset */
    --slatewave-bg-3: #0f172a;       /* deepest surface */

    --slatewave-border: #334155;
    --slatewave-border-hover: #475569;
    --slatewave-border-muted: #1e293b;

    --slatewave-text: #e2e8f0;
    --slatewave-text-muted: #cbd5e1;
    --slatewave-text-faint: #64748b;
    --slatewave-text-on-emphasis: #0f172a;

    --slatewave-teal: #5eead4;
    --slatewave-teal-hover: #99f6e4;
    --slatewave-teal-deep: #0f766e;
    --slatewave-teal-faint: rgba(94, 234, 212, 0.15);
    --slatewave-teal-subtle: rgba(94, 234, 212, 0.08);

    --slatewave-sky: #7dd3fc;
    --slatewave-sky-strong: #38bdf8;
    --slatewave-purple: #b388ff;
    --slatewave-purple-deep: #5b21b6;
    --slatewave-amber: #fbbf24;
    --slatewave-amber-deep: #b45309;
    --slatewave-amber-faint: rgba(251, 191, 36, 0.15);
    --slatewave-rose: #fb7185;
    --slatewave-rose-deep: #7f1d1d;
    --slatewave-rose-faint: rgba(251, 113, 133, 0.15);

    /* ---------- Modern Primer tokens (bgColor / fgColor) ---------- */
    --bgColor-default: var(--slatewave-bg-0) !important;
    --bgColor-muted: var(--slatewave-bg-1) !important;
    --bgColor-inset: var(--slatewave-bg-2) !important;
    --bgColor-emphasis: var(--slatewave-bg-3) !important;
    --bgColor-disabled: var(--slatewave-bg-2) !important;

    --bgColor-neutral-muted: rgba(148, 163, 184, 0.12) !important;
    --bgColor-neutral-emphasis: var(--slatewave-text-faint) !important;
    --bgColor-neutral-emphasisPlus: var(--slatewave-text-muted) !important;

    --bgColor-accent-muted: var(--slatewave-teal-faint) !important;
    --bgColor-accent-emphasis: var(--slatewave-teal-deep) !important;
    --bgColor-success-muted: var(--slatewave-teal-subtle) !important;
    --bgColor-success-emphasis: var(--slatewave-teal-deep) !important;
    --bgColor-attention-muted: var(--slatewave-amber-faint) !important;
    --bgColor-attention-emphasis: var(--slatewave-amber-deep) !important;
    --bgColor-severe-muted: var(--slatewave-amber-faint) !important;
    --bgColor-severe-emphasis: var(--slatewave-amber-deep) !important;
    --bgColor-danger-muted: var(--slatewave-rose-faint) !important;
    --bgColor-danger-emphasis: var(--slatewave-rose) !important;
    --bgColor-open-muted: var(--slatewave-teal-faint) !important;
    --bgColor-open-emphasis: var(--slatewave-teal-deep) !important;
    --bgColor-closed-muted: var(--slatewave-rose-faint) !important;
    --bgColor-closed-emphasis: var(--slatewave-rose) !important;
    --bgColor-done-muted: rgba(179, 136, 255, 0.15) !important;
    --bgColor-done-emphasis: var(--slatewave-purple-deep) !important;
    --bgColor-upsell-muted: rgba(179, 136, 255, 0.15) !important;
    --bgColor-upsell-emphasis: var(--slatewave-purple-deep) !important;

    --fgColor-default: var(--slatewave-text) !important;
    --fgColor-muted: var(--slatewave-text-muted) !important;
    --fgColor-onEmphasis: var(--slatewave-text-on-emphasis) !important;
    --fgColor-onInverse: var(--slatewave-text-on-emphasis) !important;
    --fgColor-disabled: var(--slatewave-text-faint) !important;
    --fgColor-link: var(--slatewave-teal) !important;
    --fgColor-accent: var(--slatewave-teal) !important;
    --fgColor-success: var(--slatewave-teal) !important;
    --fgColor-attention: var(--slatewave-amber) !important;
    --fgColor-severe: var(--slatewave-amber) !important;
    --fgColor-danger: var(--slatewave-rose) !important;
    --fgColor-open: var(--slatewave-teal) !important;
    --fgColor-closed: var(--slatewave-rose) !important;
    --fgColor-done: var(--slatewave-purple) !important;
    --fgColor-upsell: var(--slatewave-purple) !important;

    --borderColor-default: var(--slatewave-border) !important;
    --borderColor-muted: var(--slatewave-border-muted) !important;
    --borderColor-emphasis: var(--slatewave-border-hover) !important;
    --borderColor-neutral-emphasis: var(--slatewave-text-faint) !important;
    --borderColor-accent-muted: var(--slatewave-teal-faint) !important;
    --borderColor-accent-emphasis: var(--slatewave-teal) !important;
    --borderColor-success-muted: var(--slatewave-teal-faint) !important;
    --borderColor-success-emphasis: var(--slatewave-teal) !important;
    --borderColor-attention-muted: var(--slatewave-amber-faint) !important;
    --borderColor-attention-emphasis: var(--slatewave-amber) !important;
    --borderColor-severe-emphasis: var(--slatewave-amber) !important;
    --borderColor-danger-muted: var(--slatewave-rose-faint) !important;
    --borderColor-danger-emphasis: var(--slatewave-rose) !important;
    --borderColor-open-emphasis: var(--slatewave-teal) !important;
    --borderColor-closed-emphasis: var(--slatewave-rose) !important;
    --borderColor-done-emphasis: var(--slatewave-purple) !important;

    /* ---------- Buttons (modern Primer) ---------- */
    --button-default-bgColor-rest: var(--slatewave-bg-1) !important;
    --button-default-bgColor-hover: var(--slatewave-border) !important;
    --button-default-bgColor-active: var(--slatewave-border-hover) !important;
    --button-default-fgColor-rest: var(--slatewave-text) !important;
    --button-default-borderColor-rest: var(--slatewave-border) !important;
    --button-default-borderColor-hover: var(--slatewave-border-hover) !important;

    --button-primary-bgColor-rest: var(--slatewave-teal-deep) !important;
    --button-primary-bgColor-hover: var(--slatewave-teal) !important;
    --button-primary-bgColor-active: var(--slatewave-teal-hover) !important;
    --button-primary-fgColor-rest: var(--slatewave-text-on-emphasis) !important;
    --button-primary-borderColor-rest: var(--slatewave-teal-deep) !important;
    --button-primary-borderColor-hover: var(--slatewave-teal) !important;

    --button-danger-bgColor-rest: var(--slatewave-bg-1) !important;
    --button-danger-bgColor-hover: var(--slatewave-rose-deep) !important;
    --button-danger-fgColor-rest: var(--slatewave-rose) !important;
    --button-danger-fgColor-hover: var(--slatewave-text) !important;

    --button-invisible-bgColor-rest: transparent !important;
    --button-invisible-bgColor-hover: var(--slatewave-teal-faint) !important;
    --button-invisible-fgColor-rest: var(--slatewave-text) !important;
    --button-invisible-fgColor-hover: var(--slatewave-teal-hover) !important;

    --button-counter-bgColor-rest: var(--slatewave-bg-2) !important;

    /* ---------- Controls (selectMenu, overlays) ---------- */
    --overlay-bgColor: var(--slatewave-bg-1) !important;
    --overlay-borderColor: var(--slatewave-border) !important;
    --overlay-backdrop-bgColor: rgba(15, 23, 42, 0.6) !important;

    --selectMenu-bgColor-active: var(--slatewave-teal-faint) !important;
    --controlKnob-bgColor-rest: var(--slatewave-text-muted) !important;
    --control-bgColor-rest: var(--slatewave-bg-1) !important;
    --control-bgColor-hover: var(--slatewave-bg-2) !important;
    --control-bgColor-active: var(--slatewave-bg-3) !important;
    --control-borderColor-rest: var(--slatewave-border) !important;
    --control-borderColor-emphasis: var(--slatewave-teal) !important;
    --control-fgColor-rest: var(--slatewave-text) !important;
    --control-fgColor-placeholder: var(--slatewave-text-faint) !important;

    /* ---------- Avatars / counters ---------- */
    --avatar-bgColor: var(--slatewave-bg-1) !important;
    --avatar-borderColor: var(--slatewave-border-muted) !important;
    --counter-borderColor: transparent !important;

    /* ---------- Diffs ---------- */
    --diffBlob-additionLine-bgColor: rgba(94, 234, 212, 0.10) !important;
    --diffBlob-additionWord-bgColor: rgba(94, 234, 212, 0.22) !important;
    --diffBlob-additionNum-bgColor: rgba(94, 234, 212, 0.15) !important;
    --diffBlob-additionFg: var(--slatewave-text) !important;
    --diffBlob-deletionLine-bgColor: rgba(251, 113, 133, 0.10) !important;
    --diffBlob-deletionWord-bgColor: rgba(251, 113, 133, 0.22) !important;
    --diffBlob-deletionNum-bgColor: rgba(251, 113, 133, 0.15) !important;
    --diffBlob-deletionFg: var(--slatewave-text) !important;
    --diffBlob-hunkNum-bgColor-rest: var(--slatewave-bg-2) !important;
    --diffBlob-expander-iconFgColor-rest: var(--slatewave-text-muted) !important;

    /* ---------- Header ---------- */
    --header-bgColor: var(--slatewave-bg-3) !important;
    --header-fgColor-default: var(--slatewave-text) !important;
    --header-fgColor-logo: var(--slatewave-text) !important;
    --header-borderColor-divider: var(--slatewave-border) !important;

    /* ---------- Legacy Primer tokens (still used in many surfaces) ---------- */
    --color-canvas-default: var(--slatewave-bg-0) !important;
    --color-canvas-overlay: var(--slatewave-bg-1) !important;
    --color-canvas-inset: var(--slatewave-bg-2) !important;
    --color-canvas-subtle: var(--slatewave-bg-1) !important;

    --color-fg-default: var(--slatewave-text) !important;
    --color-fg-muted: var(--slatewave-text-muted) !important;
    --color-fg-subtle: var(--slatewave-text-faint) !important;
    --color-fg-on-emphasis: var(--slatewave-text-on-emphasis) !important;

    --color-accent-fg: var(--slatewave-teal) !important;
    --color-accent-emphasis: var(--slatewave-teal-deep) !important;
    --color-accent-muted: var(--slatewave-teal-faint) !important;
    --color-accent-subtle: var(--slatewave-teal-subtle) !important;

    --color-success-fg: var(--slatewave-teal) !important;
    --color-success-emphasis: var(--slatewave-teal-deep) !important;
    --color-success-muted: var(--slatewave-teal-faint) !important;
    --color-success-subtle: var(--slatewave-teal-subtle) !important;

    --color-attention-fg: var(--slatewave-amber) !important;
    --color-attention-emphasis: var(--slatewave-amber-deep) !important;
    --color-attention-muted: var(--slatewave-amber-faint) !important;
    --color-attention-subtle: var(--slatewave-amber-faint) !important;

    --color-severe-fg: var(--slatewave-amber) !important;
    --color-severe-emphasis: var(--slatewave-amber-deep) !important;
    --color-severe-muted: var(--slatewave-amber-faint) !important;

    --color-danger-fg: var(--slatewave-rose) !important;
    --color-danger-emphasis: var(--slatewave-rose) !important;
    --color-danger-muted: var(--slatewave-rose-faint) !important;
    --color-danger-subtle: var(--slatewave-rose-faint) !important;

    --color-open-fg: var(--slatewave-teal) !important;
    --color-open-emphasis: var(--slatewave-teal-deep) !important;
    --color-open-muted: var(--slatewave-teal-faint) !important;
    --color-open-subtle: var(--slatewave-teal-subtle) !important;

    --color-closed-fg: var(--slatewave-rose) !important;
    --color-closed-emphasis: var(--slatewave-rose) !important;
    --color-closed-muted: var(--slatewave-rose-faint) !important;

    --color-done-fg: var(--slatewave-purple) !important;
    --color-done-emphasis: var(--slatewave-purple-deep) !important;
    --color-done-muted: rgba(179, 136, 255, 0.15) !important;

    --color-sponsors-fg: var(--slatewave-purple) !important;
    --color-sponsors-emphasis: var(--slatewave-purple-deep) !important;
    --color-sponsors-muted: rgba(179, 136, 255, 0.15) !important;

    --color-border-default: var(--slatewave-border) !important;
    --color-border-muted: var(--slatewave-border-muted) !important;
    --color-border-subtle: var(--slatewave-border-muted) !important;

    /* Buttons (legacy) */
    --color-btn-text: var(--slatewave-text) !important;
    --color-btn-bg: var(--slatewave-bg-1) !important;
    --color-btn-border: var(--slatewave-border) !important;
    --color-btn-hover-bg: var(--slatewave-border) !important;
    --color-btn-hover-border: var(--slatewave-border-hover) !important;
    --color-btn-active-bg: var(--slatewave-border-hover) !important;
    --color-btn-selected-bg: var(--slatewave-bg-2) !important;
    --color-btn-counter-bg: var(--slatewave-bg-2) !important;

    --color-btn-primary-text: var(--slatewave-text-on-emphasis) !important;
    --color-btn-primary-bg: var(--slatewave-teal-deep) !important;
    --color-btn-primary-border: var(--slatewave-teal-deep) !important;
    --color-btn-primary-hover-bg: var(--slatewave-teal) !important;
    --color-btn-primary-hover-border: var(--slatewave-teal) !important;
    --color-btn-primary-selected-bg: var(--slatewave-teal-hover) !important;
    --color-btn-primary-disabled-text: rgba(15, 23, 42, 0.6) !important;
    --color-btn-primary-disabled-bg: var(--slatewave-teal-deep) !important;

    --color-btn-danger-text: var(--slatewave-rose) !important;
    --color-btn-danger-hover-text: var(--slatewave-text) !important;
    --color-btn-danger-hover-bg: var(--slatewave-rose-deep) !important;
    --color-btn-danger-hover-border: var(--slatewave-rose) !important;

    /* Action list */
    --color-action-list-item-default-hover-bg: var(--slatewave-teal-subtle) !important;
    --color-action-list-item-default-active-bg: var(--slatewave-teal-faint) !important;
    --color-action-list-item-default-selected-bg: var(--slatewave-teal-faint) !important;

    /* Side nav (Settings pages, file browser sidebar) */
    --color-side-nav-bg: var(--slatewave-bg-1) !important;
    --color-side-nav-selected-bg: var(--slatewave-teal-faint) !important;

    /* Header (legacy) */
    --color-header-bg: var(--slatewave-bg-3) !important;
    --color-header-text: var(--slatewave-text) !important;
    --color-header-logo: var(--slatewave-text) !important;

    /* Notifications */
    --color-notifications-button-text: var(--slatewave-text) !important;
    --color-notifications-button-hover-text: var(--slatewave-teal) !important;

    /* Diff (legacy) */
    --color-diff-blob-addition-num-text: var(--slatewave-text) !important;
    --color-diff-blob-addition-num-bg: rgba(94, 234, 212, 0.15) !important;
    --color-diff-blob-addition-line-bg: rgba(94, 234, 212, 0.10) !important;
    --color-diff-blob-addition-word-bg: rgba(94, 234, 212, 0.22) !important;
    --color-diff-blob-deletion-num-text: var(--slatewave-text) !important;
    --color-diff-blob-deletion-num-bg: rgba(251, 113, 133, 0.15) !important;
    --color-diff-blob-deletion-line-bg: rgba(251, 113, 133, 0.10) !important;
    --color-diff-blob-deletion-word-bg: rgba(251, 113, 133, 0.22) !important;
    --color-diff-blob-hunk-num-bg: var(--slatewave-bg-2) !important;
    --color-diff-blob-expander-icon: var(--slatewave-text-muted) !important;
    --color-diffstat-addition-bg: var(--slatewave-teal) !important;
    --color-diffstat-deletion-bg: var(--slatewave-rose) !important;

    /* ---------- Syntax highlighting (matches the VSCode Slatewave theme) ---------- */
    --color-prettylights-syntax-comment: var(--slatewave-text-faint) !important;
    --color-prettylights-syntax-constant: var(--slatewave-rose) !important;
    --color-prettylights-syntax-entity: var(--slatewave-sky) !important;
    --color-prettylights-syntax-storage-modifier-import: var(--slatewave-text) !important;
    --color-prettylights-syntax-entity-tag: var(--slatewave-teal) !important;
    --color-prettylights-syntax-keyword: var(--slatewave-sky-strong) !important;
    --color-prettylights-syntax-string: var(--slatewave-teal) !important;
    --color-prettylights-syntax-variable: var(--slatewave-text) !important;
    --color-prettylights-syntax-brackethighlighter-unmatched: var(--slatewave-rose) !important;
    --color-prettylights-syntax-invalid-illegal-text: var(--slatewave-text) !important;
    --color-prettylights-syntax-invalid-illegal-bg: var(--slatewave-rose-deep) !important;
    --color-prettylights-syntax-carriage-return-text: var(--slatewave-text) !important;
    --color-prettylights-syntax-carriage-return-bg: var(--slatewave-rose-deep) !important;
    --color-prettylights-syntax-string-regexp: var(--slatewave-purple) !important;
    --color-prettylights-syntax-markup-list: var(--slatewave-amber) !important;
    --color-prettylights-syntax-markup-heading: var(--slatewave-teal) !important;
    --color-prettylights-syntax-markup-italic: var(--slatewave-text-muted) !important;
    --color-prettylights-syntax-markup-bold: var(--slatewave-text) !important;
    --color-prettylights-syntax-markup-deleted-text: var(--slatewave-text) !important;
    --color-prettylights-syntax-markup-deleted-bg: rgba(251, 113, 133, 0.15) !important;
    --color-prettylights-syntax-markup-inserted-text: var(--slatewave-text) !important;
    --color-prettylights-syntax-markup-inserted-bg: rgba(94, 234, 212, 0.15) !important;
    --color-prettylights-syntax-markup-changed-text: var(--slatewave-text) !important;
    --color-prettylights-syntax-markup-changed-bg: rgba(251, 191, 36, 0.15) !important;
    --color-prettylights-syntax-markup-ignored-text: var(--slatewave-text-muted) !important;
    --color-prettylights-syntax-markup-ignored-bg: var(--slatewave-bg-2) !important;
    --color-prettylights-syntax-meta-diff-range: var(--slatewave-purple) !important;
    --color-prettylights-syntax-brackethighlighter-angle: var(--slatewave-text-muted) !important;
    --color-prettylights-syntax-sublimelinter-gutter-mark: var(--slatewave-border) !important;
    --color-prettylights-syntax-constant-other-reference-link: var(--slatewave-teal) !important;
    --color-prettylights-syntax-sublime-other: var(--slatewave-text) !important;

    /* ---------- Code editor (Monaco-style on PR composer, gist) ---------- */
    --color-codemirror-text: var(--slatewave-text) !important;
    --color-codemirror-bg: var(--slatewave-bg-0) !important;
    --color-codemirror-gutters-bg: var(--slatewave-bg-0) !important;
    --color-codemirror-guttermarker-text: var(--slatewave-text-muted) !important;
    --color-codemirror-guttermarker-subtle-text: var(--slatewave-text-faint) !important;
    --color-codemirror-linenumber-text: var(--slatewave-text-faint) !important;
    --color-codemirror-cursor: var(--slatewave-teal) !important;
    --color-codemirror-selection-bg: rgba(94, 234, 212, 0.25) !important;
    --color-codemirror-activeline-bg: rgba(94, 234, 212, 0.06) !important;
    --color-codemirror-matchingbracket-text: var(--slatewave-teal) !important;
    --color-codemirror-lines-bg: var(--slatewave-bg-0) !important;
    --color-codemirror-syntax-comment: var(--slatewave-text-faint) !important;
    --color-codemirror-syntax-constant: var(--slatewave-rose) !important;
    --color-codemirror-syntax-entity: var(--slatewave-sky) !important;
    --color-codemirror-syntax-keyword: var(--slatewave-sky-strong) !important;
    --color-codemirror-syntax-storage: var(--slatewave-sky-strong) !important;
    --color-codemirror-syntax-string: var(--slatewave-teal) !important;
    --color-codemirror-syntax-support: var(--slatewave-teal) !important;
    --color-codemirror-syntax-variable: var(--slatewave-text) !important;
  }

  /* ---------- Targeted rules for surfaces the variables miss ---------- */

  /* Selection: teal, not the GitHub purple-ish default */
  ::selection {
    background: rgba(94, 234, 212, 0.25);
  }

  /* Tighten up the global header divider to match the slate palette */
  .AppHeader,
  header.Header {
    border-bottom-color: var(--slatewave-border);
  }

  /* Subtle teal underline on hovered links — keeps text-decoration but in palette */
  a:hover {
    text-decoration-color: var(--slatewave-teal-hover);
  }

  /* Active tab indicator — make it teal everywhere a UnderlineNav is used */
  .UnderlineNav-item[aria-current],
  .UnderlineNav-item[aria-selected="true"],
  .UnderlineNav-item.selected {
    border-bottom-color: var(--slatewave-teal) !important;
  }

  /* Open-issue / open-PR icon on the issue list — the SVG fill ignores some
   * vars in older list views. Force the teal. */
  .octicon-issue-opened.color-fg-success,
  .octicon-git-pull-request.color-fg-success,
  .octicon-git-pull-request-draft {
    color: var(--slatewave-teal) !important;
  }

  /* Code lines in blob view: keep the active line highlight teal */
  .blob-code-hunk,
  .blob-num-hunk {
    background-color: var(--slatewave-bg-2);
    color: var(--slatewave-text-muted);
  }

  /* Pinned-repo cards in the dashboard — the existing rule lays down a
   * gradient that washes out on slate. Drop it for a flat slate panel. */
  .pinned-item-list-item-content {
    background-image: none;
  }
}
